/**
 * mechsense-core.js  v1.1.0
 * MechSense 共通計算ライブラリ
 * 対応: JIS B 2704（コイルばね）、JIS B 1083（ボルト締付）
 * 予定: JIS B 1234（共振点）
 *
 * 動作環境: ブラウザ・Android WebView・Node.js（共通）
 * © 2026 BoltSense (t.makoto). All rights reserved.
 */

(function (root, factory) {
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = factory();   // Node.js / CommonJS
  } else {
    root.MechSense = factory();   // ブラウザ / Android WebView
  }
}(typeof self !== 'undefined' ? self : this, function () {

  // ─────────────────────────────────────────────
  // Spring モジュール（JIS B 2704 コイルばね）
  // ─────────────────────────────────────────────

  const SPRING_MATERIALS = {
    'SW-B': {
      name: 'SW-B（硬鋼線）',
      jis: 'JIS G3521',
      G: 78500,   // 横弾性係数 (MPa)
      sigma: [
        { d: 0.5,  s: 1910 }, { d: 0.6,  s: 1810 }, { d: 0.7,  s: 1770 }, { d: 0.8,  s: 1770 },
        { d: 1.0,  s: 1720 }, { d: 1.2,  s: 1670 }, { d: 1.4,  s: 1620 }, { d: 1.6,  s: 1570 },
        { d: 1.8,  s: 1520 }, { d: 2.0,  s: 1470 }, { d: 2.3,  s: 1420 }, { d: 2.6,  s: 1420 },
        { d: 2.9,  s: 1370 }, { d: 3.2,  s: 1370 }, { d: 3.5,  s: 1370 }, { d: 4.0,  s: 1370 },
        { d: 4.5,  s: 1320 }, { d: 5.0,  s: 1320 }, { d: 6.0,  s: 1230 }, { d: 7.0,  s: 1180 },
        { d: 8.0,  s: 1180 }, { d: 10.0, s: 1130 }, { d: 12.0, s: 1080 }, { d: 13.0, s: 1030 },
      ]
    },
    'SW-C': {
      name: 'SW-C（硬鋼線）',
      jis: 'JIS G3521',
      G: 78500,
      sigma: [
        { d: 0.5,  s: 2210 }, { d: 0.6,  s: 2110 }, { d: 0.7,  s: 2060 }, { d: 0.8,  s: 2010 },
        { d: 1.0,  s: 1960 }, { d: 1.2,  s: 1910 }, { d: 1.4,  s: 1860 }, { d: 1.6,  s: 1810 },
        { d: 1.8,  s: 1770 }, { d: 2.0,  s: 1720 }, { d: 2.3,  s: 1670 }, { d: 2.6,  s: 1670 },
        { d: 2.9,  s: 1620 }, { d: 3.2,  s: 1570 }, { d: 3.5,  s: 1570 }, { d: 4.0,  s: 1570 },
        { d: 4.5,  s: 1520 }, { d: 5.0,  s: 1520 }, { d: 6.0,  s: 1420 }, { d: 7.0,  s: 1370 },
        { d: 8.0,  s: 1370 }, { d: 10.0, s: 1320 }, { d: 12.0, s: 1270 }, { d: 13.0, s: 1230 },
      ]
    },
    'SWP-A': {
      name: 'SWP-A（ピアノ線）',
      jis: 'JIS G3522',
      G: 78500,
      sigma: [
        { d: 0.5,  s: 2300 }, { d: 0.6,  s: 2210 }, { d: 0.7,  s: 2160 }, { d: 0.8,  s: 2110 },
        { d: 1.0,  s: 2060 }, { d: 1.2,  s: 2010 }, { d: 1.4,  s: 1960 }, { d: 1.6,  s: 1910 },
        { d: 1.8,  s: 1860 }, { d: 2.0,  s: 1810 }, { d: 2.3,  s: 1770 }, { d: 2.6,  s: 1770 },
        { d: 2.9,  s: 1720 }, { d: 3.2,  s: 1670 }, { d: 3.5,  s: 1670 }, { d: 4.0,  s: 1670 },
        { d: 4.5,  s: 1620 }, { d: 5.0,  s: 1620 }, { d: 6.0,  s: 1520 }, { d: 7.0,  s: 1470 },
        { d: 8.0,  s: 1470 }, { d: 10.0, s: 1420 },
      ]
    },
    'SWO-A': {
      name: 'SWO-A（オイルテンパー線）',
      jis: 'JIS G3560',
      G: 78500,
      sigma: [
        { d: 2.0,  s: 1570 }, { d: 2.3,  s: 1570 }, { d: 2.6,  s: 1570 }, { d: 2.9,  s: 1520 },
        { d: 3.2,  s: 1470 }, { d: 3.5,  s: 1470 }, { d: 4.0,  s: 1420 }, { d: 4.5,  s: 1370 },
        { d: 5.0,  s: 1370 }, { d: 6.0,  s: 1320 }, { d: 7.0,  s: 1270 }, { d: 8.0,  s: 1270 },
        { d: 10.0, s: 1230 }, { d: 12.0, s: 1180 },
      ]
    },
    'SWOSC-B': {
      name: 'SWOSC-B（シリコンクロム鋼線）',
      jis: 'JIS G3560',
      G: 78500,
      sigma: [
        { d: 1.0,  s: 1960 }, { d: 1.2,  s: 1960 }, { d: 1.4,  s: 1960 }, { d: 1.6,  s: 1960 },
        { d: 1.8,  s: 1960 }, { d: 2.0,  s: 1910 }, { d: 2.3,  s: 1910 }, { d: 2.6,  s: 1910 },
        { d: 2.9,  s: 1910 }, { d: 3.2,  s: 1860 }, { d: 3.5,  s: 1860 }, { d: 4.0,  s: 1810 },
        { d: 4.5,  s: 1760 }, { d: 5.0,  s: 1760 }, { d: 6.0,  s: 1710 }, { d: 7.0,  s: 1660 },
        { d: 8.0,  s: 1660 }, { d: 10.0, s: 1660 }, { d: 12.0, s: 1660 },
      ]
    },
    'SUS304-WPB': {
      name: 'SUS304-WPB（ステンレス線）',
      jis: 'JIS G4314',
      G: 68500,
      sigma: [
        { d: 0.5,  s: 2000 }, { d: 0.6,  s: 1950 }, { d: 0.8,  s: 1950 }, { d: 1.0,  s: 1850 },
        { d: 1.4,  s: 1750 }, { d: 2.0,  s: 1650 }, { d: 2.6,  s: 1550 }, { d: 4.0,  s: 1450 },
        { d: 6.0,  s: 1350 }, { d: 8.0,  s: 1270 }, { d: 10.0, s: 980  }, { d: 12.0, s: 880  },
      ]
    },
  };

  /**
   * JIS最小引張強さ σB を取得する。
   * d が表内の値より大きい場合は最大線径の値を返す（保守的）。
   * @param {string} matKey - 材料キー
   * @param {number} d      - 線径 (mm)
   * @returns {number} σB (MPa)
   */
  function springGetSigmaB(matKey, d) {
    const tbl = SPRING_MATERIALS[matKey] && SPRING_MATERIALS[matKey].sigma;
    if (!tbl) return 1200;
    for (let i = 0; i < tbl.length; i++) {
      if (d <= tbl[i].d) return tbl[i].s;
    }
    return tbl[tbl.length - 1].s;
  }

  /**
   * コイルばね計算（JIS B 2704 圧縮コイルばね）
   *
   * @param {object} params
   * @param {number} params.d     - 線径 (mm)
   * @param {number} params.D     - コイル中心径 (mm)
   * @param {number} params.Na   - 有効巻数
   * @param {number} params.P    - 荷重 (N)
   * @param {string} params.mat  - 材料キー（SPRING_MATERIALS のキー）
   *
   * @returns {SpringResult}
   *   error    {string|null}   バリデーションエラーメッセージ（null = 正常）
   *   d, D, Na, P, mat         入力値そのまま
   *   G        {number}        横弾性係数 (MPa)
   *   sigmaB   {number}        JIS最小引張強さ (MPa)
   *   C        {number}        ばね指数 (D/d)
   *   K        {number}        Wahl係数
   *   k        {number}        ばね定数 (N/mm)
   *   delta    {number}        たわみ (mm)
   *   tau      {number}        最大せん断応力 (MPa)
   *   ratio    {number}        応力比 τ/σB
   *   Lc       {number}        密着高さ (mm)
   *   Do       {number}        外径 (mm)
   *   Di       {number}        内径 (mm)
   *   Nt       {number}        総巻数
   *   stressOK {boolean}       応力比 ≤ 0.45
   *   cRange   {boolean}       4 ≤ C ≤ 14
   *   isSafe   {boolean}       stressOK && cRange
   *   status   {string}        'OK' | 'NG_STRESS' | 'NG_CRANGE'
   *   warnings {string[]}      警告メッセージ一覧
   */
  function springCalc(params) {
    const { d, D, Na, P, mat: matKey } = params;

    const result = {
      error: null,
      d, D, Na, P, mat: matKey,
      G: null, sigmaB: null,
      C: null, K: null, k: null, delta: null, tau: null,
      ratio: null, Lc: null, Do: null, Di: null, Nt: null,
      stressOK: false, cRange: false, isSafe: false,
      status: 'NG_STRESS',
      warnings: [],
    };

    // バリデーション
    const material = SPRING_MATERIALS[matKey];
    if (!material) {
      result.error = `材料データが見つかりません: ${matKey}`;
      return result;
    }
    if (isNaN(d) || d <= 0)  { result.error = '線径 d が無効です'; return result; }
    if (isNaN(D) || D <= 0)  { result.error = '中心径 D が無効です'; return result; }
    if (isNaN(Na) || Na <= 0){ result.error = '有効巻数 Na が無効です'; return result; }
    if (isNaN(P) || P < 0)   { result.error = '荷重 P が無効です'; return result; }

    const G      = material.G;
    const sigmaB = springGetSigmaB(matKey, d);
    const C      = D / d;

    if (C < 2) {
      result.error = `ばね指数 C = ${C.toFixed(2)} < 2（線径が大きすぎます）`;
      return result;
    }

    // JIS B 2704 計算式
    const K     = (4 * C - 1) / (4 * C - 4) + 0.615 / C;
    const k     = G * Math.pow(d, 4) / (8 * Math.pow(D, 3) * Na);
    const delta = k > 0 ? P / k : 0;
    const tau   = 8 * P * D * K / (Math.PI * Math.pow(d, 3));
    const ratio = tau / sigmaB;
    const Lc    = (Na + 2) * d;
    const Do    = D + d;
    const Di    = D - d;
    const Nt    = Na + 2;

    // 安全判定
    const stressOK = ratio <= 0.45;
    const cRange   = C >= 4 && C <= 14;
    const isSafe   = stressOK && cRange;

    let status;
    if (isSafe)           status = 'OK';
    else if (!stressOK)   status = 'NG_STRESS';
    else                  status = 'NG_CRANGE';

    // 警告メッセージ
    const warnings = [];
    if (!stressOK)
      warnings.push(`応力超過: τ/σB = ${ratio.toFixed(4)} > 0.45。線径を太くするかコイル径を大きくしてください。`);
    if (C < 4)
      warnings.push(`ばね指数 C = ${C.toFixed(2)} < 4（推奨範囲）。コイル径を大きくするか線径を細くしてください。`);
    if (C > 14)
      warnings.push(`ばね指数 C = ${C.toFixed(2)} > 14（推奨範囲）。座屈リスクが増加します。`);

    return Object.assign(result, {
      G, sigmaB,
      C, K, k, delta, tau, ratio, Lc, Do, Di, Nt,
      stressOK, cRange, isSafe, status, warnings,
    });
  }

  const Spring = {
    /** 対応材料一覧 */
    MATERIALS: SPRING_MATERIALS,

    /**
     * JIS最小引張強さ σB を取得する。
     * @param {string} matKey
     * @param {number} d
     * @returns {number}
     */
    getSigmaB: springGetSigmaB,

    /**
     * コイルばね計算（JIS B 2704）。
     * @param {object} params - { d, D, Na, P, mat }
     * @returns {SpringResult}
     */
    calc: springCalc,
  };


  // ─────────────────────────────────────────────
  // Bolt モジュール（JIS B 1083 ボルト締付）
  // ─────────────────────────────────────────────

  // M3〜M42 JIS標準メートルねじ寸法（JIS B 1083 附属書）
  const BOLT_DATA = {
     3: { p:0.5,  d2:2.675,  d3:2.459,  As:5.03,  dw:5.5,  dh:3.4  },
     4: { p:0.7,  d2:3.545,  d3:3.242,  As:8.78,  dw:7.0,  dh:4.5  },
     5: { p:0.8,  d2:4.480,  d3:4.134,  As:14.2,  dw:8.8,  dh:5.5  },
     6: { p:1.0,  d2:5.350,  d3:4.917,  As:20.1,  dw:10.0, dh:6.6  },
     8: { p:1.25, d2:7.188,  d3:6.647,  As:36.6,  dw:13.0, dh:9.0  },
    10: { p:1.5,  d2:9.026,  d3:8.376,  As:58.0,  dw:16.0, dh:11.0 },
    12: { p:1.75, d2:10.863, d3:10.106, As:84.3,  dw:18.0, dh:13.5 },
    16: { p:2.0,  d2:14.701, d3:13.835, As:157,   dw:24.0, dh:17.5 },
    20: { p:2.5,  d2:18.376, d3:17.294, As:245,   dw:30.0, dh:22.0 },
    22: { p:2.5,  d2:20.376, d3:19.294, As:303,   dw:34.0, dh:24.0 },
    24: { p:3.0,  d2:22.051, d3:20.752, As:353,   dw:36.0, dh:26.0 },
    27: { p:3.0,  d2:25.051, d3:23.752, As:459,   dw:41.0, dh:30.0 },
    30: { p:3.5,  d2:27.727, d3:26.211, As:561,   dw:46.0, dh:33.0 },
    33: { p:3.5,  d2:30.727, d3:29.211, As:694,   dw:50.0, dh:36.0 },
    36: { p:4.0,  d2:33.402, d3:31.670, As:817,   dw:55.0, dh:39.0 },
    39: { p:4.0,  d2:36.402, d3:34.670, As:976,   dw:60.0, dh:42.0 },
    42: { p:4.5,  d2:39.077, d3:37.129, As:1121,  dw:65.0, dh:45.0 },
  };

  // ボルト強度区分（JIS B 1051 / ISO 898-1・ISO 3506）
  const BOLT_GRADES = {
    '4.6':   { Sy: 240,  Su: 400  },
    '4.8':   { Sy: 340,  Su: 420  },
    '8.8':   { Sy: 660,  Su: 830  },
    '10.9':  { Sy: 940,  Su: 1040 },
    '12.9':  { Sy: 1100, Su: 1220 },
    'A2-70': { Sy: 450,  Su: 700  },
    'A4-70': { Sy: 450,  Su: 700  },
    'A4-80': { Sy: 600,  Su: 800  },
    'A2017': { Sy: 275,  Su: 440  },
    'A5052': { Sy: 215,  Su: 265  },
    'A6061': { Sy: 275,  Su: 310  },
    'C3604': { Sy: 300,  Su: 400  },
  };

  // 被締結材（許容せん断強度 tau、許容面圧 bearing）
  const CLAMPED_MATERIALS = {
    spcc:      { tau: 340, bearing: 220, name: '鋼板 SPCC'    },
    steel:     { tau: 400, bearing: 220, name: '鋼 SS400'     },
    s45c:      { tau: 690, bearing: 380, name: '鋼 S45C'      },
    sus304:    { tau: 520, bearing: 185, name: 'SUS304'       },
    aluminum:  { tau: 310, bearing: 60,  name: 'アルミ合金'   },
    cast_iron: { tau: 200, bearing: 120, name: '鋳鉄 FC200'   },
    brass:     { tau: 390, bearing: 100, name: '真鍮'         },
    resin:     { tau: 65,  bearing: 30,  name: 'エンプラ'     },
  };

  // 摩擦条件（ねじ面 mt、座面 mw）
  const FRICTION_MAP = {
    dry:    { mt: 0.15, mw: 0.15, label: 'μ=0.15 乾燥'  },
    lube:   { mt: 0.10, mw: 0.10, label: 'μ=0.10 潤滑'  },
    grease: { mt: 0.08, mw: 0.08, label: 'μ=0.08 グリス' },
  };

  // 軟質材（座面陥没・山せん断が問題になりやすい材料）
  const SOFT_MATERIALS = new Set(['aluminum', 'cast_iron', 'brass', 'resin']);

  /**
   * ボルト締付トルク計算（JIS B 1083）
   *
   * @param {object} params
   * @param {number} params.d        - ボルト呼び径 (mm) 例: 10
   * @param {string} params.grade    - 強度区分キー 例: '10.9'
   * @param {string} params.partMat  - 被締結材キー 例: 'aluminum'
   * @param {string} params.mu       - 摩擦条件キー 例: 'dry'
   * @param {number} [params.sf=1.5] - 安全率
   * @param {number} [params.dep=1.0]- ねじ込み深さ係数（×d）
   *
   * @returns {BoltResult}
   *   error        {string|null}  バリデーションエラー（null = 正常）
   *   K            {number}       トルク係数（無次元）
   *   Fy           {number}       降伏軸力 (kN)
   *   T_lim        {number}       限界トルク (N·m)
   *   T_jis        {number}       JIS標準推奨トルク = T_lim/sf (N·m)
   *   T_rec        {number}       推奨締付トルク（被締結材を考慮） (N·m)
   *   T_range      {object}       許容範囲 { min, max } (N·m) ±10%
   *   failModes    {object[]}     破損モード一覧 [{name, F, T}] 昇順
   *   dominant     {string}       支配的破損モード名
   *   isMaterialLimit {boolean}   被締結材強度で制限されているか
   *   warnings     {string[]}     警告メッセージ
   */
  function boltCalc(params) {
    const { d, grade: grK, partMat: partMatKey, mu: muKey, sf = 1.5, dep = 1.0 } = params;

    const b = BOLT_DATA[d];
    if (!b) return { error: `ボルト径 M${d} は対応範囲外です（M3〜M42）` };
    const gr = BOLT_GRADES[grK];
    if (!gr) return { error: `強度区分 "${grK}" はデータベースにありません` };
    const clB = CLAMPED_MATERIALS[partMatKey];
    if (!clB) return { error: `被締結材 "${partMatKey}" はデータベースにありません` };
    const muData = FRICTION_MAP[muKey];
    if (!muData) return { error: `摩擦条件 "${muKey}" はデータベースにありません` };

    const { mt, mw } = muData;

    // JIS B 1083 式(2)：トルク係数 K
    const Db  = (b.dw + b.dh) / 2;
    const K   = b.p / (2 * Math.PI * d) + 0.577 * mt * b.d2 / d + mw * Db / (2 * d);
    const Knd = K * d;

    // JIS B 1083 式(7)：降伏軸力 Fy (kN)
    const At       = b.p / (2 * Math.PI) + 0.577 * mt * b.d2;
    const dAs      = Math.sqrt(4 * b.As / Math.PI);
    const Fy_denom = 1 + 3 * Math.pow(3 / dAs * At, 2);
    const Fy       = gr.Sy * b.As / Math.sqrt(Fy_denom) / 1000;

    // JIS B 1083 式(8)：限界トルク T_lim (N·m)
    const T_lim = Knd * Fy;

    // 破損モード別限界軸力 (kN)
    const nTh  = Math.max(1, (dep * d - 0.5 * b.p) / b.p);   // 有効ねじ山数
    const bArea = (Math.PI / 4) * (b.dw * b.dw - b.dh * b.dh);
    const Fbrk = gr.Su * b.As / 1000;                                    // ボルト破断
    const Fstr = clB.tau * Math.PI * d * 0.5 * b.p * nTh * 0.577 / 1000; // 山せん断
    const FbA  = clB.bearing * bArea / 1000;                             // 座面陥没

    const failModes = [
      { name: 'ボルト破断', F: Fbrk },
      { name: '山せん断',   F: Fstr },
      { name: '座面陥没',   F: FbA  },
    ].sort((a, b) => a.F - b.F).map(fm => ({ name: fm.name, F: fm.F, T: fm.F * Knd }));

    const dominant = failModes[0];
    const T_jis = T_lim / sf;
    const isSoft = SOFT_MATERIALS.has(partMatKey);
    const T_mat  = dominant.T / sf;
    const T_rec  = isSoft ? Math.min(T_jis, T_mat) : T_jis;
    const isMaterialLimit = isSoft && T_mat < T_jis;

    const warnings = [];
    if (isMaterialLimit) {
      if (dominant.name === '山せん断') {
        warnings.push(`相手部材の山せん断強度により制限（JIS標準 ${T_jis.toFixed(2)} N·m → ${T_rec.toFixed(2)} N·m）`);
        warnings.push('ねじ込み深さを増やすか、相手材の強化を推奨');
      } else if (dominant.name === '座面陥没') {
        warnings.push(`相手部材の許容面圧により制限（JIS標準 ${T_jis.toFixed(2)} N·m → ${T_rec.toFixed(2)} N·m）`);
      }
    }

    return {
      error: null,
      // 入力
      d, grade: grK, partMat: partMatKey, mu: muKey, sf, dep,
      // 材料定数
      Sy: gr.Sy, Su: gr.Su,
      // ボルト寸法
      p: b.p, d2: b.d2, As: b.As, dw: b.dw, dh: b.dh,
      // 中間値
      K, Fy,
      // 主要結果
      T_lim,
      T_jis,
      T_rec,
      T_range: { min: +(T_rec * 0.9).toFixed(2), max: +(T_rec * 1.1).toFixed(2) },
      // 破損解析
      failModes,
      dominant: dominant.name,
      isMaterialLimit,
      warnings,
    };
  }

  const Bolt = {
    BOLTS:              BOLT_DATA,
    GRADES:             BOLT_GRADES,
    CLAMPED_MATERIALS:  CLAMPED_MATERIALS,
    FRICTION:           FRICTION_MAP,

    /**
     * ボルト締付トルク計算（JIS B 1083）。
