// ─────────────────────────────────────────────
// Resonance モジュール（JIS B 2704 附属書 コイルばね固有振動数）
// ─────────────────────────────────────────────

// 材料密度 (g/cm³)
const SPRING_DENSITY = {
  'SW-B':       7.85,  // 硬鋼線 JIS G3521
  'SW-C':       7.85,
  'SWP-A':      7.85,  // ピアノ線 JIS G3522
  'SWO-A':      7.85,  // オイルテンパー線 JIS G3560
  'SWOSC-B':    7.85,  // シリコンクロム鋼線 JIS G3560
  'SUS304-WPB': 7.93,  // ステンレス線 JIS G4314
};

/**
 * コイルばね固有振動数計算（JIS B 2704 附属書 サージング判定）
 *
 * サージング（固有振動数）式:
 *   fn = (d × 10³) / (2π × Na × D²) × √(G × 10³ / ρ)  [Hz]
 *   （d, D: mm  G: MPa  ρ: g/cm³）
 *
 * @param {object} params
 * @param {number} params.d      - 線径 (mm)
 * @param {number} params.D      - コイル中心径 (mm)
 * @param {number} params.Na    - 有効巻数
 * @param {string} params.mat   - 材料キー（SPRING_MATERIALS のキー）
 * @param {number} [params.rpm] - 動作回転速度（min⁻¹）。省略時は比較なし
 * @param {number} [params.mass]- ばね上の荷重質量 (kg)。省略時はシステム共振省略
 *
 * @returns {ResonanceResult}
 *   error          {string|null}  バリデーションエラー（null = 正常）
 *   k              {number}       ばね定数 (N/mm)
 *   m_spring       {number}       ばね自重 (kg)
 *   fn_surge       {number}       固有振動数（サージング） (Hz)
 *   fn_surge_rpm   {number}       固有振動数 (min⁻¹)
 *   fn_modes       {number[]}     第1〜4次固有振動数 [Hz]
 *   fn_system      {number|null}  システム共振数 [Hz]（mass 指定時）
 *   fn_system_rpm  {number|null}  システム共振数 [min⁻¹]（mass 指定時）
 *   f_op           {number|null}  動作周波数 [Hz]（rpm 指定時）
 *   ratio_surge    {number|null}  f_op / fn_surge（rpm 指定時）
 *   status         {string|null}  'SAFE'|'WARNING'|'DANGER'（rpm 指定時）
 *   f_safe_max     {number}       安全動作上限周波数（fn_surge × 0.7） [Hz]
 *   warnings       {string[]}     警告メッセージ一覧
 */
function resonanceCalc(params) {
  const { d, D, Na, mat: matKey, rpm, mass } = params;

  const result = {
    error: null,
    d, D, Na, mat: matKey,
    rpm: (rpm !== undefined && rpm !== null) ? rpm : null,
    mass: (mass !== undefined && mass !== null) ? mass : null,
    k: null, m_spring: null,
    fn_surge: null, fn_surge_rpm: null, fn_modes: null,
    fn_system: null, fn_system_rpm: null,
    f_op: null, ratio_surge: null, status: null,
    f_safe_max: null,
    warnings: [],
  };

  const material = SPRING_MATERIALS[matKey];
  if (!material) {
    result.error = `材料データが見つかりません: ${matKey}`;
    return result;
  }
  if (isNaN(d) || d <= 0)   { result.error = '線径 d が無効です'; return result; }
  if (isNaN(D) || D <= 0)   { result.error = '中心径 D が無効です'; return result; }
  if (isNaN(Na) || Na <= 0) { result.error = '有効巻数 Na が無効です'; return result; }

  const C = D / d;
  if (C < 2) {
    result.error = `ばね指数 C = ${C.toFixed(2)} < 2（線径が大きすぎます）`;
    return result;
  }

  const G   = material.G;
  const rho = SPRING_DENSITY[matKey] || 7.85;
  const Nt  = Na + 2;

  // ばね定数 (N/mm) — JIS B 2704 式(1)
  const k = G * Math.pow(d, 4) / (8 * Math.pow(D, 3) * Na);

  // ばね自重 (kg): m = ρ×10⁻⁶ × (π/4)d² × π×D×Nt  [d,D:mm]
  const m_spring = rho * 1e-6 * (Math.PI / 4) * d * d * Math.PI * D * Nt;

  // 固有振動数（サージング）: fn = d×10³/(2π×Na×D²) × √(G×10³/ρ) [Hz]
  const fn_surge     = (d * 1e3) / (2 * Math.PI * Na * D * D) * Math.sqrt(G * 1e3 / rho);
  const fn_surge_rpm = fn_surge * 60;
  const fn_modes     = [1, 2, 3, 4].map(n => fn_surge * n);
  const f_safe_max   = fn_surge * 0.7;

  // システム共振（ばね＋外部質量）: fn_sys = (1/2π) × √(k×1000/mass)
  let fn_system = null, fn_system_rpm = null;
  if (result.mass !== null && !isNaN(result.mass) && result.mass > 0) {
    fn_system     = (1 / (2 * Math.PI)) * Math.sqrt(k * 1000 / result.mass);
    fn_system_rpm = fn_system * 60;
  }

  // 動作点判定
  let f_op = null, ratio_surge = null, status = null;
  if (result.rpm !== null && !isNaN(result.rpm) && result.rpm > 0) {
    f_op         = result.rpm / 60;
    ratio_surge  = f_op / fn_surge;

    if (ratio_surge > 0.8) {
      status = 'DANGER';
      result.warnings.push(
        `危険: 動作周波数 ${f_op.toFixed(1)} Hz = 固有振動数の ${(ratio_surge * 100).toFixed(0)}%。` +
        'サージング発生の可能性があります。ばね定数・巻数・線径を見直してください。'
      );
    } else if (ratio_surge > 0.65) {
      status = 'WARNING';
      result.warnings.push(
        `注意: 動作周波数が固有振動数の ${(ratio_surge * 100).toFixed(0)}%（推奨上限: 70%以下）。` +
        '設計変更を検討してください。'
      );
    } else {
      status = 'SAFE';
    }
  }

  if (Na < 3) {
    result.warnings.push('有効巻数 Na < 3: 固有振動数の算出精度が低下する可能性があります。');
  }

  return Object.assign(result, {
    k, m_spring,
    fn_surge, fn_surge_rpm, fn_modes,
    fn_system, fn_system_rpm,
    f_op, ratio_surge, status,
    f_safe_max,
  });
}

const Resonance = {
  /** 材料密度データ（g/cm³） */
  DENSITY: SPRING_DENSITY,

  /**
   * コイルばね固有振動数・サージング判定（JIS B 2704 附属書）。
   * @param {object} params - { d, D, Na, mat, rpm?, mass? }
   * @returns {ResonanceResult}
   */
  calc: resonanceCalc,
};

